function validateAadhaar(number) {
  // Remove spaces
  const clean = number.replace(/\\s/g, '');
  
  // Check length
  if (clean.length !== 12) {
    return { 
      valid: false, 
      error: 'Must be 12 digits' 
    };
  }
  
  // Check numeric
  if (!/^\\d{12}$/.test(clean)) {
    return { 
      valid: false, 
      error: 'Only digits allowed' 
    };
  }
  
  // Verhoeff checksum validation
  if (!verhoeffCheck(clean)) {
    return { 
      valid: false, 
      error: 'Invalid Aadhaar number' 
    };
  }
  
  return { valid: true };
}

